mapper.select:
SELECT TDS.ID, TDSI.ID SHIPVOYAGE_ITEM_ID, TDS.SHIP_NAME, TDSI.VOYAGE, TDS.SHIP_NAME || '_' || TDSI.VOYAGE SHIP_NAME_VOYAGE, TDSI.LOAD_UNLOAD, TDSI.TRADE_TYPE, MDD_TRADE_TYPE.DICT_LABEL TRADE_TYPE_LABEL, TDSI.CUSTOMER_ID, TDSI.CUSTOMER_NAME, TDS.BERTH_TIME, TDS.LEAVE_BERTH_TIME, TDS.LEAVE_PORT_TIME, TDSI.SHIP_STATUS_NAME, TDSI.CARGO_CATEGORY_NAME, CASE WHEN ( SELECT COUNT( * ) FROM T_BUS_HANDOVERLIST TBH WHERE TDSI.ID = TBH.SHIPVOYAGE_ITEM_ID ) > 0 THEN '1' ELSE '0' END IS_HAVE_HANDOVERLIST, CASE WHEN ( SELECT COUNT( * ) FROM T_BUS_HANDOVERLIST TBH WHERE TDSI.ID = TBH.SHIPVOYAGE_ITEM_ID ) > 0 THEN '已生成' ELSE '未生成' END IS_HAVE_HANDOVERLIST_LABEL FROM T_DIS_SHIPVOYAGE_ITEM TDSI JOIN T_DIS_SHIPVOYAGE TDS ON TDSI.SHIPVOYAGE_ID = TDS.ID JOIN M_DICT_DATA MDD_TRADE_TYPE ON (MDD_TRADE_TYPE.DICT_TYPE = 'TRADE_TYPE' AND MDD_TRADE_TYPE.STATUS = '1' AND TDSI.TRADE_TYPE = MDD_TRADE_TYPE.DICT_VALUE)
(TDS.WHARF = '1' or TDS.WHARF is null) and TDSI.LOAD_UNLOAD = '装'
AND TDSI.ID = #{shipvoyageItemId, jdbcType=BIGINT}
AND ((TDS.SHIP_NAME || '_' || TDSI.VOYAGE) like #{shipOrVoyage_like, jdbcType=VARCHAR})
AND TDS.SHIP_NAME LIKE #{shipName_like}
AND TDSI.VOYAGE LIKE #{voyage_like}
AND TDSI.SHIP_STATUS_CODE = #{shipStatusCode, jdbcType=VARCHAR}
and TDSI.CUSTOMER_ID = #{customerId}
AND TDSI.CARGO_CATEGORY_NAME = #{cargoCategoryName, jdbcType=VARCHAR}
AND TDS.LEAVE_PORT_TIME >= #{beginLeavePortTime,jdbcType=TIMESTAMP}
AND TDS.LEAVE_PORT_TIME <= #{endLeavePortTime,jdbcType=TIMESTAMP}
AND TDSI.ID IN ( SELECT TBT.SHIPVOYAGE_ITEM_ID FROM T_BUS_TRUST TBT JOIN T_BUS_TRUST_CARGO TBTC ON TBT.ID = TBTC.TRUST_ID JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID
TBCI.CARGO_INFO_NO like #{cargoInfoNo_like, jdbcType=VARCHAR}
)
ORDER BY CASE WHEN TDS.BERTH_TIME IS NULL THEN 1 ELSE 0 END ASC, TDS.BERTH_TIME DESC

SELECT A1.ID, A1.TYPE, A1.CARGO_INFO_ID, A1.TRUST_ID, A1.TRUST_CARGO_ID, A1.SHIPVOYAGE_ID, A1.SHIPVOYAGE_ITEM_ID, A1.SHIP_NAME, A1.VOYAGE, A1.TRADE_TYPE, A1.LOAD_UNLOAD, A1.CARGO_OWNER_ID, A1.CARGO_OWNER_NAME, A1.CARGO_AGENT_ID, A1.CARGO_AGENT_NAME, A1.CARGO_CODE, A1.CARGO_NAME, A1.QUANTITY, A1.TON, A1.VOLUME_TON, A1.TICKET_NUM, A1.STATEMENT_STATUS_CODE, A1.STATEMENT_STATUS_NAME, A1.REMARK, A1.CREATE_BY, A1.CREATE_BY_NAME, A1.CREATE_TIME, A1.UPDATE_BY, A1.UPDATE_BY_NAME, A1.UPDATE_TIME, A2.CARGO_INFO_NO, A1.DELIVERY_NUMBERS FROM T_BUS_HANDOVERLIST A1 LEFT JOIN T_BUS_CARGO_INFO A2 ON A1.CARGO_INFO_ID = A2.ID
AND A1.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId, jdbcType=BIGINT}
AND A1.TRUST_ID = #{trustId, jdbcType=BIGINT}

WITH TBTC AS (SELECT ID, CARGO_INFO_ID, BUSINESS_NO FROM T_BUS_TRUST_CARGO) SELECT TBCI.ID, TBCI.SHIPVOYAGE_ID, TBCI.SHIPVOYAGE_ITEM_ID, TBCI.SCN, TBCI.SHIP_NAME, TBCI.CARGO_INFO_NO, TBCI.CARGO_OWNER_ID, TBCI.CARGO_OWNER_NAME, TBCI.CARGO_AGENT_ID, TBCI.CARGO_AGENT_NAME, TBCI.CARGO_CODE, TBCI.CARGO_NAME, TBCI.TRADE_TYPE, TBCI.PACKING_CODE, TBCI.PACKING_NAME, TBCI.COMPANY_ID, TBCI.COMPANY_NAME, TBCI.PARENT_ID, TBCI.ROOT_ID, TBCI.QUANTITY, TBCI.TON, TBCI.RIGHTS_QUANTITY, TBCI.SURPLUS_RIGHTS_QUANTITY, TBCI.IS_CLEAR, TBCI.CLEAR_BY, TBCI.CLEAR_BY_NAME, TBCI.CLEAR_DATE, TBCI.CREATE_BY, TBCI.CREATE_BY_NAME, TBCI.CREATE_TIME, TBCI.UPDATE_BY, TBCI.UPDATE_BY_NAME, TBCI.UPDATE_TIME, (SELECT MIN(TBTC.ID) FROM TBTC WHERE TBCI.ID = TBTC.CARGO_INFO_ID) "trustCargoId" -- (SELECT SUM(V.WEIGHT_GOODS) -- FROM TBTC -- JOIN V_WEIGHT_INFO V -- ON V.PLAN_NO = TBTC.BUSINESS_NO AND V.IS_OLD = '否' -- WHERE TBCI.ID = TBTC.CARGO_INFO_ID) "weightGoods" FROM T_BUS_TRUST TBT JOIN T_BUS_TRUST_CARGO TBTC ON TBT.ID = TBTC.TRUST_ID JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID
AND TBT.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId, jdbcType=BIGINT}
AND TBT.ID = #{trustId, jdbcType=BIGINT}
GROUP BY TBCI.ID, TBCI.SHIPVOYAGE_ID, TBCI.SHIPVOYAGE_ITEM_ID, TBCI.SCN, TBCI.SHIP_NAME, TBCI.CARGO_INFO_NO, TBCI.CARGO_OWNER_ID, TBCI.CARGO_OWNER_NAME, TBCI.CARGO_AGENT_ID, TBCI.CARGO_AGENT_NAME, TBCI.CARGO_CODE, TBCI.CARGO_NAME, TBCI.TRADE_TYPE, TBCI.PACKING_CODE, TBCI.PACKING_NAME, TBCI.COMPANY_ID, TBCI.COMPANY_NAME, TBCI.PARENT_ID, TBCI.ROOT_ID, TBCI.QUANTITY, TBCI.TON, TBCI.RIGHTS_QUANTITY, TBCI.SURPLUS_RIGHTS_QUANTITY, TBCI.IS_CLEAR, TBCI.CLEAR_BY, TBCI.CLEAR_BY_NAME, TBCI.CLEAR_DATE, TBCI.CREATE_BY, TBCI.CREATE_BY_NAME, TBCI.CREATE_TIME, TBCI.UPDATE_BY, TBCI.UPDATE_BY_NAME, TBCI.UPDATE_TIME
UNION SELECT TBCI.ID, TBCI.SHIPVOYAGE_ID, TBCI.SHIPVOYAGE_ITEM_ID, TBCI.SCN, TBCI.SHIP_NAME, TBCI.CARGO_INFO_NO, TBCI.CARGO_OWNER_ID, TBCI.CARGO_OWNER_NAME, TBCI.CARGO_AGENT_ID, TBCI.CARGO_AGENT_NAME, TBCI.CARGO_CODE, TBCI.CARGO_NAME, TBCI.TRADE_TYPE, TBCI.PACKING_CODE, TBCI.PACKING_NAME, TBCI.COMPANY_ID, TBCI.COMPANY_NAME, TBCI.PARENT_ID, TBCI.ROOT_ID, TBCI.QUANTITY, TBCI.TON, TBCI.RIGHTS_QUANTITY, TBCI.SURPLUS_RIGHTS_QUANTITY, TBCI.IS_CLEAR, TBCI.CLEAR_BY, TBCI.CLEAR_BY_NAME, TBCI.CLEAR_DATE, TBCI.CREATE_BY, TBCI.CREATE_BY_NAME, TBCI.CREATE_TIME, TBCI.UPDATE_BY, TBCI.UPDATE_BY_NAME, TBCI.UPDATE_TIME, (SELECT MIN(TBTC.ID) FROM TBTC WHERE TBCI.ID = TBTC.CARGO_INFO_ID) "trustCargoId" FROM T_BUS_CARGO_INFO TBCI WHERE TBCI.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId, jdbcType=BIGINT}

SELECT TBCI.ID, TBCI.SHIPVOYAGE_ID, TBCI.SHIPVOYAGE_ITEM_ID, TBCI.SCN, TBCI.SHIP_NAME, TBCI.CARGO_INFO_NO, TBCI.CARGO_OWNER_ID, TBCI.CARGO_OWNER_NAME, TBCI.CARGO_AGENT_ID, TBCI.CARGO_AGENT_NAME, TBCI.CARGO_CODE, TBCI.CARGO_NAME, TBCI.TRADE_TYPE, TBCI.PACKING_CODE, TBCI.PACKING_NAME, TBCI.COMPANY_ID, TBCI.COMPANY_NAME, TBCI.PARENT_ID, TBCI.ROOT_ID, TBCI.QUANTITY, TBCI.TON, TBCI.RIGHTS_QUANTITY, TBCI.SURPLUS_RIGHTS_QUANTITY, TBCI.IS_CLEAR, TBCI.CLEAR_BY, TBCI.CLEAR_BY_NAME, TBCI.CLEAR_DATE, TBCI.CREATE_BY, TBCI.CREATE_BY_NAME, TBCI.CREATE_TIME, TBCI.UPDATE_BY, TBCI.UPDATE_BY_NAME, TBCI.UPDATE_TIME, MIN( TBTC.ID ) TRUST_CARGO_ID, SUM(V.WEIGHT_GOODS) WEIGHT_GOODS FROM T_BUS_TRUST TBT JOIN T_BUS_TRUST_CARGO TBTC ON TBT.ID = TBTC.TRUST_ID JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID LEFT JOIN V_WEIGHT_INFO V ON V.PLAN_NO = TBTC.BUSINESS_NO AND V.IS_OLD = '否'
AND TBTC.CARGO_NAME = #{cargoCategoryName}
GROUP BY TBCI.ID, TBCI.SHIPVOYAGE_ID, TBCI.SHIPVOYAGE_ITEM_ID, TBCI.SCN, TBCI.SHIP_NAME, TBCI.CARGO_INFO_NO, TBCI.CARGO_OWNER_ID, TBCI.CARGO_OWNER_NAME, TBCI.CARGO_AGENT_ID, TBCI.CARGO_AGENT_NAME, TBCI.CARGO_CODE, TBCI.CARGO_NAME, TBCI.TRADE_TYPE, TBCI.PACKING_CODE, TBCI.PACKING_NAME, TBCI.COMPANY_ID, TBCI.COMPANY_NAME, TBCI.PARENT_ID, TBCI.ROOT_ID, TBCI.QUANTITY, TBCI.TON, TBCI.RIGHTS_QUANTITY, TBCI.SURPLUS_RIGHTS_QUANTITY, TBCI.IS_CLEAR, TBCI.CLEAR_BY, TBCI.CLEAR_BY_NAME, TBCI.CLEAR_DATE, TBCI.CREATE_BY, TBCI.CREATE_BY_NAME, TBCI.CREATE_TIME, TBCI.UPDATE_BY, TBCI.UPDATE_BY_NAME, TBCI.UPDATE_TIME

