FROM T_BUS_HANDOVERLIST
WHERE SHIPVOYAGE_ITEM_ID = #{id, jdbcType=BIGINT} OR TRUST_ID = #{id, jdbcType=BIGINT} OR ID = #{id, jdbcType=BIGINT}

