    	SELECT
			*
		FROM
			T_BUS_HANDOVERLIST


				AND SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId}


				AND TRUST_ID = #{trustId}

    	SELECT
			"COUNT"(A."ID")
		FROM
