		LEFT JOIN T_BUS_HANDOVERLIST b ON b. ID = A .HANDOVERLIST_ID
		WHERE
			b.SHIPVOYAGE_ITEM_ID = #{id, jdbcType=BIGINT} 
			OR b.TRUST_ID = #{id, jdbcType=BIGINT}
			OR A.HANDOVERLIST_ID = #{id, jdbcType=BIGINT}

mapper.update:
begin
UPDATE T_BUS_HANDOVERLIST
DELIVERY_NUMBERS= #{entity.deliveryNumbers, jdbcType=INTEGER}, QUANTITY = #{entity.quantity, jdbcType=INTEGER}, TON = #{entity.ton, jdbcType=DECIMAL}, VOLUME_TON = #{entity.volumeTon, jdbcType=DECIMAL}, TICKET_NUM = #{entity.ticketNum, jdbcType=INTEGER}, REMARK = #{entity.remark, jdbcType=VARCHAR}, UPDATE_BY = #{entity.loginUserId, jdbcType=BIGINT}, UPDATE_BY_NAME = #{entity.loginUserName, jdbcType=VARCHAR}, UPDATE_TIME = #{entity.now}
id = #{entity.id};
end;

mapper.select:
SELECT
    A1.SHIPVOYAGE_ITEM_ID "shipvoyageItemId",A1.CARGO_NAME "cargoName",A1.TON "ton"
FROM T_BUS_HANDOVERLIST A1 LEFT JOIN T_BUS_CARGO_INFO A2 ON A1.CARGO_INFO_ID = A2.ID

    A1.SHIPVOYAGE_ITEM_ID IN (

        #{id}

    )

SELECT
sum(TBH.TON)
FROM T_DIS_SHIPVOYAGE_ITEM TDSI
JOIN T_DIS_SHIPVOYAGE TDS ON TDSI.SHIPVOYAGE_ID = TDS.ID
LEFT JOIN T_BUS_HANDOVERLIST TBH ON TDSI.ID = TBH.SHIPVOYAGE_ITEM_ID

    TDS.WHARF = '1' or TDS.WHARF is null

        AND TDSI.ID = #{shipvoyageItemId, jdbcType=BIGINT}



        AND ((TDS.SHIP_NAME || '_' || TDSI.VOYAGE) like #{shipOrVoyage_like, jdbcType=VARCHAR})


        AND TDSI.SHIP_STATUS_CODE = #{shipStatusCode, jdbcType=VARCHAR}


        and TDSI.CUSTOMER_ID = #{customerId}


        AND TDSI.CARGO_CATEGORY_NAME = #{cargoCategoryName, jdbcType=VARCHAR}


        AND TDS.LEAVE_PORT_TIME >= #{beginLeavePortTime,jdbcType=TIMESTAMP}


        AND TDS.LEAVE_PORT_TIME <= #{endLeavePortTime,jdbcType=TIMESTAMP}


        AND (TDS.IS_START_WORK IS NULL OR TDS.IS_START_WORK = #{isStartWork, jdbcType=VARCHAR})


        AND TDSI.ID IN (
        SELECT TBT.SHIPVOYAGE_ITEM_ID
        FROM T_BUS_TRUST TBT
        JOIN T_BUS_TRUST_CARGO TBTC ON TBT.ID = TBTC.TRUST_ID
        JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID


            TBCI.CARGO_INFO_NO like #{cargoInfoNo_like, jdbcType=VARCHAR}

        )


ORDER BY CASE WHEN TDS.BERTH_TIME IS NULL THEN 1 ELSE 0 END ASC, TDS.BERTH_TIME DESC
